import{_ as i,c as t,o as a,a3 as o}from"./chunks/framework.IjbGqw7S.js";const c=JSON.parse('{"title":"What is MMRL","description":"","frontmatter":{},"headers":[],"relativePath":"guide/index.md","filePath":"en/guide/index.md"}'),n={name:"guide/index.md"};function s(l,e,r,d,p,u){return a(),t("div",{"data-pagefind-body":!0},e[0]||(e[0]=[o('<h1 id="what-is-mmrl" tabindex="-1">What is MMRL <a class="header-anchor" href="#what-is-mmrl" aria-label="Permalink to &quot;What is MMRL&quot;">​</a></h1><p>Magisk Module Repo Loader (MMRL) is an advanced, open-source Android application developed by Der_Googler, designed to streamline the management of modules for Magisk, KernelSU, and APatch. This highly configurable tool empowers users to efficiently handle their own module repositories, all within an ad-free environment.</p><h2 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h2><ul><li><p><strong>Comprehensive Root Manager Support</strong>: MMRL offers full compatibility with Magisk, KernelSU, and APatch, providing users with a versatile platform for root management.</p></li><li><p><strong>User-Friendly Interface</strong>: The application boasts a user-centric design, featuring edge-to-edge support and dynamic app themes, ensuring a seamless and intuitive user experience.</p></li><li><p><strong>Bulk Module Installation</strong>: Users can install multiple modules simultaneously, whether sourced online or from local storage, enhancing efficiency in module management.</p></li><li><p><strong>Module Dependency Management</strong>: MMRL simplifies the installation process by automatically handling module dependencies, ensuring that all necessary components are in place for optimal functionality.</p></li><li><p><strong>Customizable Module Pages</strong>: The application allows for personalized module pages, enabling the addition of categories, screenshots, icons, covers, and other content to tailor the presentation to user preferences.</p></li><li><p><strong>Transparency of Included Files</strong>: MMRL provides a detailed breakdown of all files within modules, including APKs and service files, ensuring users have full visibility into the components of each module.</p></li><li><p><strong>Analytics Dashboard</strong>: An integrated analytics dashboard displays module-related insights on the homepage, offering valuable information on module usage and trends.</p></li><li><p><strong>Command-Line Interface (MMRL-CLI)</strong>: For users who prefer terminal-based interactions, MMRL offers a Command-Line Interface, MMRL-CLI, which facilitates seamless module installation and management directly from the terminal.</p></li></ul><h2 id="how-to-use" tabindex="-1">How to Use <a class="header-anchor" href="#how-to-use" aria-label="Permalink to &quot;How to Use&quot;">​</a></h2><p>To get started with MMRL, follow these steps:</p><ol><li><p><strong>Installation</strong>:</p><ul><li>Download the latest version of MMRL from the official website or a trusted repository.</li><li>Install the application on your Android device.</li></ul></li><li><p><strong>Adding Repositories</strong>:</p><ul><li>Open MMRL and navigate to the repository management section.</li><li>Add your desired module repositories by entering their URLs.</li></ul></li><li><p><strong>Managing Modules</strong>:</p><ul><li>Browse through the available modules in your added repositories.</li><li>Select modules to install, update, enable, disable, or remove as needed.</li></ul></li></ol><p>For a comprehensive guide on installation and usage, please refer to the <a href="https://github.com/MMRLApp/MMRL" target="_blank" rel="noreferrer">MMRL GitHub Repository</a>.</p><h2 id="how-to-build" tabindex="-1">How to Build <a class="header-anchor" href="#how-to-build" aria-label="Permalink to &quot;How to Build&quot;">​</a></h2><p>If you&#39;re interested in building MMRL from source, follow these steps:</p><ol><li><p><strong>Prerequisites</strong>:</p><ul><li>Ensure you have Android Studio installed on your development machine.</li><li>Clone the MMRL repository from GitHub:<div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/MMRLApp/MMRL.git</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li></ul></li><li><p><strong>Building the Application</strong>:</p><ul><li>Open the project in Android Studio.</li><li>Sync the project to download necessary dependencies.</li><li>Build the project to generate the APK file.</li></ul></li></ol><p>For detailed instructions and troubleshooting, please refer to the <a href="https://github.com/MMRLApp/MMRL" target="_blank" rel="noreferrer">MMRL GitHub Repository</a>.</p><h2 id="discussion" tabindex="-1">Discussion <a class="header-anchor" href="#discussion" aria-label="Permalink to &quot;Discussion&quot;">​</a></h2><p>Join the community discussion to share experiences, seek assistance, and stay updated with the latest developments:</p><ul><li><strong>Telegram</strong>: <a href="https://t.me/MMRLApp" target="_blank" rel="noreferrer">@MMRLApp</a></li></ul><p>Engaging with the community can provide valuable insights and support as you navigate the features and functionalities of MMRL.</p>',16)]))}const g=i(n,[["render",s]]);export{c as __pageData,g as default};
